section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/frontend-design.json",
  "title": "Frontend Design Variant Exploration",
  "type": "object",
  "required": [
    "artefact_id",
    "brief_path",
    "variants",
    "selected_variant",
    "selection_rationale",
    "storybook_stories",
    "component_paths",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "brief_path": {
      "type": "string",
      "minLength": 1
    },
    "variants": {
      "type": "array",
      "minItems": 3,
      "description": "list of {slug, path, rationale, axes_differentiated}"
    },
    "selected_variant": {
      "type": "string",
      "minLength": 1
    },
    "selection_rationale": {
      "type": "string",
      "minLength": 1
    },
    "storybook_stories": {
      "type": "array",
      "minItems": 1
    },
    "component_paths": {
      "type": "array",
      "minItems": 1
    }
  },
  "additionalProperties": false
}
